mapper.update:
update item
title = #{title}, description = #{description}, price = #{price}, original_price = #{originalPrice}, category_id = #{categoryId}, item_condition = #{itemCondition}, image_url = #{imageUrl}, status = #{status}, update_time = #{updateTime}, update_user = #{updateUser},
where item_id = #{itemId}

mapper.select:
select i.item_id, i.title, i.price, i.original_price, i.image_url,
       i.view_count, i.status, i.item_condition, i.create_time,
       u.username as seller_name, c.name as category_name
from item i
left join user u on i.seller_id = u.user_id
left join category c on i.category_id = c.category_id


        and match(i.title, i.description) against(#{keyword} in natural language mode)


        and i.category_id = #{categoryId}


        and i.item_condition = #{itemCondition}


        and i.status = #{status}


        and i.price >= #{minPrice}


        and i.price <= #{maxPrice}




        order by i.view_count desc, i.create_time desc


        order by i.price asc, i.create_time desc


        order by i.price desc, i.create_time desc


        order by i.create_time desc

select i.item_id, i.title, i.price, i.original_price, i.image_url,
       i.view_count, i.status, i.item_condition, i.create_time,
       u.username as seller_name, c.name as category_name
from item i
left join user u on i.seller_id = u.user_id
left join category c on i.category_id = c.category_id
where i.item_id in

    #{id}


    and i.category_id = #{dto.categoryId}


    and i.status = #{dto.status}


    and i.item_condition = #{dto.itemCondition}


    and i.price >= #{dto.minPrice}


    and i.price <= #{dto.maxPrice}



        order by i.view_count desc, i.create_time desc


        order by i.price asc, i.create_time desc


        order by i.price desc, i.create_time desc


        order by i.create_time desc
